{
  "name": "TEXT-GENERATION",
  "display_name": { "en": "Text Generation", "es": "Generación de Texto" },
  "description": "AI-powered text generation and question answering"
}

{
  "context": {
    "networkId": "beckn.one/testnet",
    "action": "confirm",
    "version": "2.0.0",
    "bapId": "bap.example.com",
    "bapUri": "http://onix-bap:8081/bap/receiver",
    "bppId": "bpp.example.com",
    "bppUri": "http://onix-bpp:8082/bpp/receiver",
    "transactionId": "{{transaction_id}}",
    "messageId": "{{message_id}}",
    "timestamp": "{{timestamp}}",
    "ttl": "PT30S"
  },
  "message": {
    "contract": {
      "id": "{{contract_id}}",
      "commitments": [
        {
          "id": "commitment-001",
          "status": { "descriptor": { "code": "DRAFT" } },
          "resources": [
            {
              "id": "{{agent_id}}",
              "descriptor": {
                "name": "Groq Text Generator",
                "code": "TEXT-GENERATION",
                "longDesc": "Describeme quien fue Roberto Bolaño y quienes son los detectives salvajes"
              },
              "quantity": { "unitQuantity": 1, "unitCode": "EXECUTION" }
            }
          ],
          "offer": {
            "id": "offer-agent-{{agent_id}}",
            "resourceIds": ["{{agent_id}}"]
          }
        }
      ],
      "participants": [
        {
          "id": "participant-buyer-001",
          "descriptor": { "name": "{{buyer_name}}", "code": "buyer" }
        }
      ],
      "performance": [{ "id": "perf-001" }],
      "settlements": [{ "id": "settlement-001", "status": "COMPLETE" }]
    }
  }
}
